INSERT INTO quiz_question (id, word_bank_id, contextual_cloze, chinese_translation, correct_answer, distractor1, distractor2, distractor3, explanation_root_affix, explanation_mnemonic) VALUES
('d07c1a62-2f88-58b7-84e3-54a187e4298e', 'e5cf7677-1873-4e7a-ae65-3de4832151b1', 'Please ___ an umbrella because it might rain.', '請帶一把傘，因為可能會下雨。', 'take', 'give', 'make', 'eat', 'take 表示「拿」或「帶」。', 'take (拿) + an umbrella (傘) → 帶傘。'),
('db33cdfe-9e8e-53a0-b9ab-5dc1a8b36e36', '2148b226-a44f-453e-ac23-6e310525b3c4', 'He is a talented musician ___ a professional actor.', '他是一位有才華的音樂家，也是一位專業的演員。', 'and', 'but', 'or', 'yet', '連接詞，用於連接兩個對等的身份或特質。', '身份 A + 身份 B'),
('af7bff74-c6ab-530a-9936-4800bb1ca0aa', '056bbf79-2f62-44e1-88e9-19e796ece41a', 'It takes a strong ___ to persevere when facing such extreme difficulties.', '面對如此極端的困難時，需要強大的意志力才能堅持下去。', 'will', 'mind', 'dream', 'gift', '名詞，表示意志或決心。', 'will → 意志 (名詞用法)');
